'use strict';

// Semantic-version precedence sorting. See docs/registry.md for the contract
// and docs/conventions.md for the precedence rules (numeric core fields,
// pre-release lower than release, build metadata ignored for precedence).
//
// Returns the input version strings sorted ascending by SemVer precedence,
// each original string preserved verbatim (build metadata is not stripped),
// without mutating the input array.
function sortVersions(versions) {
  return versions.slice().sort((a, b) => compareVersions(a, b));
}

function parseVersion(v) {
  // Strip build metadata before comparison
  const buildIdx = v.indexOf('+');
  const withoutBuild = buildIdx === -1 ? v : v.slice(0, buildIdx);

  const dashIdx = withoutBuild.indexOf('-');
  const corePart = dashIdx === -1 ? withoutBuild : withoutBuild.slice(0, dashIdx);
  const preReleasePart = dashIdx === -1 ? null : withoutBuild.slice(dashIdx + 1);

  const [major, minor, patch] = corePart.split('.').map(Number);
  const preRelease = preReleasePart === null ? null : preReleasePart.split('.');

  return { major, minor, patch, preRelease };
}

function compareVersions(a, b) {
  const pa = parseVersion(a);
  const pb = parseVersion(b);

  if (pa.major !== pb.major) return pa.major - pb.major;
  if (pa.minor !== pb.minor) return pa.minor - pb.minor;
  if (pa.patch !== pb.patch) return pa.patch - pb.patch;

  // Pre-release has lower precedence than release
  if (pa.preRelease === null && pb.preRelease === null) return 0;
  if (pa.preRelease === null) return 1;
  if (pb.preRelease === null) return -1;

  // Compare pre-release identifiers left to right
  const len = Math.max(pa.preRelease.length, pb.preRelease.length);
  for (let i = 0; i < len; i++) {
    if (i >= pa.preRelease.length) return -1;
    if (i >= pb.preRelease.length) return 1;

    const ia = pa.preRelease[i];
    const ib = pb.preRelease[i];
    const numA = /^\d+$/.test(ia);
    const numB = /^\d+$/.test(ib);

    if (numA && numB) {
      const diff = Number(ia) - Number(ib);
      if (diff !== 0) return diff;
    } else if (numA !== numB) {
      // Numeric identifiers have lower precedence than alphanumeric
      return numA ? -1 : 1;
    } else {
      if (ia < ib) return -1;
      if (ia > ib) return 1;
    }
  }

  return 0;
}

module.exports = { sortVersions };

